const yeniMetin = $("Extract from File").item.json.text || "";
const tumKayitlar = $("Get many database pages").all();

const normalize = (s) => {
  return s
    .toLowerCase()
    .replace(/[^\w\sğüşıöç]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
};

const getWordFreq = (text) => {
  const words = normalize(text).split(' ');
  const freq = {};
  for (const w of words) {
    if (w.length > 1) {
      freq[w] = (freq[w] || 0) + 1;
    }
  }
  return freq;
};

const cosineSimilarity = (freq1, freq2) => {
  const allWords = new Set([...Object.keys(freq1), ...Object.keys(freq2)]);

  let dot = 0;
  let norm1 = 0;
  let norm2 = 0;

  for (const word of allWords) {
    const v1 = freq1[word] || 0;
    const v2 = freq2[word] || 0;

    dot += v1 * v2;
    norm1 += v1 * v1;
    norm2 += v2 * v2;
  }

  if (norm1 === 0 || norm2 === 0) return 0;

  return (dot / (Math.sqrt(norm1) * Math.sqrt(norm2))) * 100;
};

const getSimilarity = (str1, str2) => {
  if (!str1 || !str2) return 0;

  const freq1 = getWordFreq(str1);
  const freq2 = getWordFreq(str2);

  return cosineSimilarity(freq1, freq2);
};

let enYuksekOran = 0;
let enBenzerMetin = "";
let dosyaSayisi = 0;

for (const item of tumKayitlar) {
  const eskiMetin = item.json["Analiz Edilecek Metin"] || 
                   item.json["property_analiz_edilecek_metin"] || 
                   item.json["analiz_edilecek_metin"] || "";

  const temizEskiMetin = eskiMetin.toString().trim();

  if (temizEskiMetin.length > 5) {
    dosyaSayisi++;
    const oran = getSimilarity(yeniMetin, temizEskiMetin);

    if (oran > enYuksekOran) {
      enYuksekOran = oran;
      enBenzerMetin = temizEskiMetin;
    }
  }
}

return {
  en_yuksek_oran: Math.round(enYuksekOran),
  toplam_kayit_sayisi: dosyaSayisi,
  karsilastirilan_metin_kesiti: enBenzerMetin.substring(0, 2500) || "METİN BULUNAMADI - SÜTUN ADINI KONTROL ET",
  yeni_metin_kesiti: yeniMetin.substring(0, 2500) || "PDF METNİ OKUNAMADI"
};

