try {
  // 2. JSON formatındaki metni temizle (kod bloklarını kaldır) ve objeye çevir
  const cleanJson = rawContent.replace(/```json|```/g, "").trim();
  const aiData = JSON.parse(cleanJson);

  // 3. İlk JS düğümünden gelen orijinal oran ve metin bilgilerini de al
  const jsData = $("Code in JavaScript").item.json;

  return {
    final_oran: aiData.oran || jsData.en_yuksek_oran || 0,
