    final_rapor: "Hata: AI yanıtı JSON formatında değil. Ham yanıt: " + rawContent.substring(0, 500),
    ogrenci_adi: $("On form submission").item.json["ad_soyad"] || "Hata",
    analiz_metni: $("Extract from File").item.json.text.substring(0, 2000)
  };
}
